package main

import (
	"encoding/json"
	"errors"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	webhookURL   string
	webhookMutex sync.RWMutex
)

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Status  string `json:"status"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Invalid request body",
		})
	}

	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "webhook_url is required",
		})
	}

	if err := validateWebhookURL(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Invalid URL format",
		})
	}

	if err := testWebhookURL(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Webhook URL test failed: " + err.Error(),
		})
	}

	webhookMutex.Lock()
	webhookURL = config.WebhookURL
	webhookMutex.Unlock()

	return ctx.JSON(Response{
		Status:  "success",
		Message: "Webhook configured successfully",
	})
}

func validateWebhookURL(url string) error {
	if len(url) < 10 || !(url[:7] == "http://" || url[:8] == "https://") {
		return errors.New("invalid URL scheme")
	}
	return nil
}

