	Success bool   `json:"success"`
	Message string `json:"message"`
}

func main() {
	app := fiber.New()
	app.Post("/configure-webhook", ConfigureWebhook)
	app.Listen(":3000")
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigRequest
	if err := json.Unmarshal(ctx.Body(), &req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Missing webhook_url field",
		})
	}

	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode > 299 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Received non-2xx status: %d", resp.StatusCode),
		})
	}

	// Save configuration logic would go here
