package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	webhookURL string
	configMutex sync.RWMutex
)

type ConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid URL format",
		})
	}

	// Send test request with 3-second timeout
	client := http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Validation failed: %s", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Received non-2xx response: %s", resp.Status),
		})
	}

	// Save configuration
	configMutex.Lock()
	webhookURL = req.WebhookURL
	configMutex.Unlock()

	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	fmt.Println("Server listening on :8080")
	app.Listen(":8080")
}

