package main

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	webhookURL string
	mu         sync.RWMutex
)

type ConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Status  string `json:"status"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "webhook_url is required",
		})
	}

	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Invalid URL format",
		})
	}

	httpClient := &http.Client{Timeout: 3 * time.Second}
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: fmt.Sprintf("Test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: fmt.Sprintf("Test request returned non-2xx status: %d", resp.StatusCode),
		})
	}

	mu.Lock()
	webhookURL = req.WebhookURL
	mu.Unlock()

	return ctx.JSON(Response{
		Status:  "success",
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	// Start server on port 3000
	app.Listen(":3000")
}

