package main

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	savedWebhookURL string
	webhookMutex    sync.Mutex
)

type configRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req configRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(response{
			Success: false,
			Message: "Invalid URL format",
		})
	}

	client := http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(response{
			Success: false,
			Message: fmt.Sprintf("Test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(response{
			Success: false,
			Message: fmt.Sprintf("Test request returned non-2xx status: %d", resp.StatusCode),
		})
	}

	webhookMutex.Lock()
	savedWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	return ctx.JSON(response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

