package main

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	webhookMutex      sync.Mutex
	currentWebhookURL string
)

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	parsedURL, err := url.ParseRequestURI(config.WebhookURL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid URL format",
		})
	}

	client := &http.Client{Timeout: 3 * time.Second}
	req, err := http.NewRequestWithContext(
		context.Background(),
		http.MethodGet,
		config.WebhookURL,
		nil,
	)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Failed to create request: %v", err),
		})
	}

	resp, err := client.Do(req)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Received non-2xx status: %d", resp.StatusCode),
		})
	}

	webhookMutex.Lock()
	currentWebhookURL = config.WebhookURL
	webhookMutex.Unlock()

	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	// Start server
	fmt.Println("Server listening on :3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

