package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	configuredWebhookURL string
)

func main() {
	app := fiber.New()
	app.Post("/configure-webhook", ConfigureWebhook)
	app.Listen(":3000")
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	type requestBody struct {
		WebhookURL string `json:"webhook_url"`
	}

	var body requestBody
	if err := ctx.BodyParser(&body); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid request body",
		})
	}

	if body.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(body.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook returned non-2xx status: " + resp.Status,
		})
	}

	configuredWebhookURL = body.WebhookURL

	return ctx.JSON(fiber.Map{
		"message": "Webhook configured successfully",
	})
}

