// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

var safeClient *http.Client

func init() {
	safeClient = createSafeHTTPClient()
}

func createSafeHTTPClient() *http.Client {
	transport := &http.Transport{
		DialContext: safeDialContext,
	}

	return &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}
}

func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	dialer := &net.Dialer{}
	conn, err := dialer.DialContext(ctx, network, addr)
	if err != nil {
		return nil, err
	}

	if tcpAddr, ok := conn.RemoteAddr().(*net.TCPAddr); ok {
		ip := tcpAddr.IP
		if isPrivateIP(ip) {
			conn.Close()
			return nil, fmt.Errorf("private IP address detected: %s", ip.String())
		}
	} else {
		conn.Close()
		return nil, fmt.Errorf("unexpected address type: %T", conn.RemoteAddr())
	}

	return conn, nil
}

func isPrivateIP(ip net.IP) bool {
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			(ip4[0] == 169 && ip4[1] == 254) ||
			(ip4[0] == 127)
	}
	return ip.IsLoopback() ||
		ip.IsLinkLocalUnicast() ||
		(len(ip) >= net.IPv6len && ip[0]&0xfe == 0xfc)
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	resp, err := safeClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

