	"time"

	"github.com/gofiber/fiber/v2"
)

type webhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

var savedWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config webhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	parsedURL, err := url.ParseRequestURI(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid URL",
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "URL must use http or https",
		})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Test request failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Test request returned non-2xx status: " + resp.Status,
		})
	}

	savedWebhookURL = config.WebhookURL

	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

