package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variable to store the configured webhook URL
var configuredWebhookURL string

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Invalid request body: %v", err),
		})
	}

	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful status (2xx range)
	if resp.StatusCode < 200 || resp.StatusCode > 299 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Test request returned non-success status: %s", resp.Status),
		})
	}

	// Save configuration
	configuredWebhookURL = config.WebhookURL

	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	app.Listen(":3000")
}

